return-response.set-body:
@{
                return JObject.FromObject(new {
                    issuer = "{{APIMGatewayURL}}/ms-purview-mcp",
                    authorization_endpoint = "{{APIMGatewayURL}}/ms-purview-mcp/authorize",
                    token_endpoint = "{{APIMGatewayURL}}/ms-purview-mcp/token",
                    registration_endpoint = "{{APIMGatewayURL}}/ms-purview-mcp/register",
                    jwks_uri = "https://login.microsoftonline.com/{{McpTenantId}}/discovery/v2.0/keys",
                    response_types_supported = new[] { "code" },
                    subject_types_supported = new[] { "pairwise" },
                    id_token_signing_alg_values_supported = new[] { "RS256" },
                    grant_types_supported = new[] { "authorization_code", "refresh_token" },
                    code_challenge_methods_supported = new[] { "S256" },
                    token_endpoint_auth_methods_supported = new[] { "none" },
                    scopes_supported = new[] { "{{McpScope}}", "offline_access", "openid", "profile" }
                }).ToString();
            }
